<template><div class="auth-page"><section class="auth-card glass-panel"><h1>登录直播助手</h1><p>进入银河语音工作台，管理你的AI声音、TTS与直播脚本。</p><el-form :model="form" label-position="top"><el-form-item label="用户名"><el-input v-model="form.username" size="large" placeholder="请输入用户名" /></el-form-item><el-form-item label="密码"><el-input v-model="form.password" type="password" size="large" show-password placeholder="请输入密码" /></el-form-item><el-button type="primary" size="large" style="width:100%" :loading="loading" @click="submit">登录</el-button><el-button link style="width:100%;margin-top:10px" @click="$router.push('/register')">没有账号？去注册</el-button></el-form></section></div></template>
<script setup>import { reactive, ref } from 'vue';import { useRouter } from 'vue-router';import { ElMessage } from 'element-plus';import { useUserStore } from '@/stores/user';const router=useRouter(),user=useUserStore(),loading=ref(false);const form=reactive({username:'',password:''});async function submit(){if(!form.username||!form.password)return ElMessage.warning('请填写用户名和密码');loading.value=true;try{await user.doLogin(form);ElMessage.success('登录成功');router.push('/dashboard')}finally{loading.value=false}}</script>
